import React, { useState, useRef, useEffect } from 'react';
import { Upload, Camera as CameraIcon, Loader2, CheckCircle2, AlertCircle, X } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { ClassificationResult, User } from '../types';
import { db } from '../services/db';

interface ScannerProps {
  user: User | null;
}

const Scanner: React.FC<ScannerProps> = ({ user }) => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isCameraReady, setIsCameraReady] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, []);

  const startCamera = async () => {
    setError(null);
    setIsCameraOpen(true);
    setIsCameraReady(false);

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Your browser does not support camera access.");
      }

      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'environment',
          width: { ideal: 1280 },
          height: { ideal: 720 }
        } 
      });

      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.onloadedmetadata = () => {
          setIsCameraReady(true);
        };
      }
    } catch (err: any) {
      console.error("Camera error:", err);
      let errorMsg = "Camera access was denied. Please check your browser settings and permissions.";
      if (err.name === 'NotFoundError' || err.name === 'DevicesNotFoundError') {
        errorMsg = "No camera was found on this device.";
      } else if (err.name === 'NotReadableError' || err.name === 'TrackStartError') {
        errorMsg = "The camera is already in use by another application.";
      }

      setError(errorMsg);
      setIsCameraOpen(false);
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
    setIsCameraOpen(false);
    setIsCameraReady(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current && isCameraReady) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        setImage(dataUrl);
        stopCamera();
        classifyWaste(dataUrl);
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setError("File size too large. Please upload an image under 5MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        const dataUrl = reader.result as string;
        setImage(dataUrl);
        classifyWaste(dataUrl);
      };
      reader.readAsDataURL(file);
    }
  };

  const classifyWaste = async (dataUrl: string) => {
    setLoading(true);
    setResult(null);
    setError(null);

    try {
      // Extract MIME type and base64 data correctly
      const mimeTypeMatch = dataUrl.match(/^data:(image\/[a-zA-Z]+);base64,/);
      const mimeType = mimeTypeMatch ? mimeTypeMatch[1] : 'image/jpeg';
      const base64Data = dataUrl.split(',')[1];

      if (!process.env.API_KEY) {
        throw new Error("API Key is missing. Please check environment variables.");
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: mimeType, data: base64Data } },
            { text: "Analyze this image and identify the specific waste item. Classify it strictly as one of: Organic, Recyclable, Hazardous, or General. Provide clear, concise disposal instructions based on global best practices. Confidence should be a number between 0 and 1." }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              item: { type: Type.STRING },
              category: { type: Type.STRING, description: "Must be: Organic, Recyclable, Hazardous, or General" },
              confidence: { type: Type.NUMBER },
              instructions: { type: Type.STRING }
            },
            required: ["item", "category", "confidence", "instructions"]
          }
        }
      });

      // Robustly clean the response text to handle potential markdown code blocks
      const rawText = response.text || '';
      const cleanJsonStr = rawText.replace(/```json/g, '').replace(/```/g, '').trim();

      const data = JSON.parse(cleanJsonStr) as ClassificationResult;
      setResult(data);

      if (user) {
        db.saveScan({
          item: data.item,
          category: data.category,
          confidence: data.confidence,
          instructions: data.instructions,
          userId: user.id
        });
      }
    } catch (err: any) {
      console.error("Classification Error:", err);
      if (err.message?.includes("API Key")) {
        setError("Application configuration error. Please contact support.");
      } else {
        setError("AI classification failed. This can happen due to poor lighting or obscure items. Please try again with a clearer photo.");
      }
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setImage(null);
    setResult(null);
    setError(null);
    stopCamera();
  };

  return (
    <section className="py-24 bg-gray-950">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold mb-4">Scan Your Waste</h2>
          <p className="text-gray-400 max-w-2xl mx-auto">
            Upload an image or take a photo to get instant AI-powered waste classification and disposal guidance.
            {user ? "" : " (Log in to save your history)"}
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start">
          <div className="bg-gray-900/50 border-2 border-dashed border-gray-800 rounded-3xl p-8 flex flex-col items-center justify-center min-h-[450px] transition-all hover:border-green-500/50 relative overflow-hidden">

            {isCameraOpen ? (
              <div className="w-full h-full flex flex-col items-center">
                <div className="relative w-full aspect-video bg-black rounded-2xl overflow-hidden shadow-2xl mb-6">
                  <video 
                    ref={videoRef} 
                    autoPlay 
                    playsInline 
                    muted
                    className="w-full h-full object-cover"
                  />
                  {!isCameraReady && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 backdrop-blur-sm">
                      <Loader2 className="w-10 h-10 text-green-500 animate-spin mb-2" />
                      <p className="text-xs text-gray-300">Initializing Camera...</p>
                    </div>
                  )}
                  <button 
                    onClick={stopCamera}
                    className="absolute top-4 right-4 bg-black/50 hover:bg-black p-2 rounded-full text-white transition-colors z-10"
                  >
                    <X className="w-5 h-5" />
                  </button>
                </div>
                <div className="flex space-x-4">
                  <button 
                    onClick={capturePhoto}
                    disabled={!isCameraReady}
                    className="bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-8 py-3 rounded-xl font-bold flex items-center shadow-lg transition-all"
                  >
                    <div className="w-4 h-4 rounded-full border-2 border-white mr-2" />
                    Capture Photo
                  </button>
                </div>
              </div>
            ) : image ? (
              <div className="w-full h-full relative group">
                <img src={image} alt="Upload" className="w-full h-[350px] object-cover rounded-2xl shadow-2xl" />
                {!loading && (
                  <button 
                    onClick={reset}
                    className="absolute top-4 right-4 bg-red-600/90 hover:bg-red-500 p-2 rounded-full transition-colors"
                  >
                    <X className="w-5 h-5" />
                  </button>
                )}
              </div>
            ) : (
              <div className="text-center">
                <div className="bg-gray-800 p-6 rounded-full mb-6 inline-block">
                  <Upload className="w-12 h-12 text-green-500" />
                </div>
                <h3 className="text-xl font-bold mb-2">Drop your image here</h3>
                <p className="text-gray-400 mb-8">Support JPG, PNG, WEBP (Max 5MB)</p>

                <div className="flex flex-col sm:flex-row gap-4 justify-center">
                  <input 
                    type="file" 
                    accept="image/*" 
                    className="hidden" 
                    ref={fileInputRef} 
                    onChange={handleFileChange}
                  />
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="bg-gray-800 hover:bg-gray-700 text-white px-6 py-3 rounded-xl font-bold flex items-center justify-center transition-all border border-gray-700"
                  >
                    <Upload className="w-5 h-5 mr-2" />
                    Browse Files
                  </button>
                  <button 
                    onClick={startCamera}
                    className="bg-green-600 hover:bg-green-500 text-white px-6 py-3 rounded-xl font-bold flex items-center justify-center transition-all shadow-lg shadow-green-900/20"
                  >
                    <CameraIcon className="w-5 h-5 mr-2" />
                    Use Camera
                  </button>
                </div>
              </div>
            )}

            <canvas ref={canvasRef} className="hidden" />
          </div>

          <div className="bg-gray-900 border border-gray-800 rounded-3xl p-8 min-h-[450px] flex flex-col shadow-xl">
            <h3 className="text-2xl font-bold mb-6 flex items-center">
              Classification Result
              {result && <CheckCircle2 className="w-6 h-6 ml-2 text-green-500" />}
            </h3>

            {loading ? (
              <div className="flex-grow flex flex-col items-center justify-center text-center">
                <Loader2 className="w-12 h-12 text-green-500 animate-spin mb-4" />
                <p className="text-xl font-medium animate-pulse">Analyzing waste materials...</p>
                <p className="text-gray-400 mt-2">Checking with Gemini AI for precision</p>
              </div>
            ) : result ? (
              <div className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-gray-800/50 p-4 rounded-2xl">
                    <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Identified Item</p>
                    <p className="text-xl font-bold">{result.item}</p>
                  </div>
                  <div className={`p-4 rounded-2xl border ${
                    result.category === 'Organic' ? 'bg-green-500/10 border-green-500/20 text-green-400' :
                    result.category === 'Recyclable' ? 'bg-orange-500/10 border-orange-500/20 text-orange-400' :
                    result.category === 'Hazardous' ? 'bg-red-500/10 border-red-500/20 text-red-400' :
                    'bg-blue-500/10 border-blue-500/20 text-blue-400'
                  }`}>
                    <p className="text-xs font-bold opacity-60 uppercase tracking-wider mb-1">Category</p>
                    <p className="text-xl font-bold">{result.category}</p>
                  </div>
                </div>

                <div className="bg-gray-800/50 p-6 rounded-2xl">
                  <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3">Disposal Instructions</p>
                  <p className="text-gray-300 leading-relaxed">{result.instructions}</p>
                </div>

                <div className="flex flex-col sm:flex-row gap-4 pt-4">
                  <button 
                    onClick={reset}
                    className="flex-grow bg-gray-800 hover:bg-gray-700 text-white py-3 rounded-xl font-bold transition-all"
                  >
                    Scan Another Item
                  </button>
                  {user && (
                    <div className="flex items-center justify-center text-xs text-green-500 font-bold bg-green-500/10 px-4 py-3 rounded-xl border border-green-500/20">
                      Saved to History
                    </div>
                  )}
                </div>
              </div>
            ) : error ? (
              <div className="flex-grow flex flex-col items-center justify-center text-center p-8 bg-red-500/5 border border-red-500/20 rounded-2xl">
                <AlertCircle className="w-12 h-12 text-red-500 mb-4" />
                <p className="text-xl font-bold text-red-400 mb-2">Notice</p>
                <p className="text-gray-400 leading-relaxed max-w-xs">{error}</p>
                <button onClick={reset} className="mt-6 text-green-500 font-bold hover:underline">Try Again</button>
              </div>
            ) : (
              <div className="flex-grow flex flex-col items-center justify-center text-center opacity-40">
                <div className="bg-gray-800 p-5 rounded-full mb-4">
                  <Upload className="w-10 h-10" />
                </div>
                <p className="text-xl font-medium">Ready for your input</p>
                <p className="text-sm mt-2">Upload or snap a photo to begin</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

