      // @ts-ignore
      await window.aistudio.openSelectKey();
      setNeedsApiKey(false); // Proceed as per guidelines
      if (image) classifyWaste(image);
    }
  };

  const startCamera = async () => {
    setError(null);
    setIsCameraOpen(true);
