import { User, SavedScan } from '../types';
import { supabase } from './supabase';

const SESSION_KEY = 'ecosort_session';

export const db = {
  // User Operations
  saveUser: async (user: User) => {
    const { data, error } = await supabase
      .from('users')
      .insert([user])
      .select()
      .single();

    if (error) throw error;
    return data;
  },

  findUserByEmail: async (email: string): Promise<User | null> => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .eq('email', email)
      .single();

    if (error && error.code !== 'PGRST116') throw error; // PGRST116 is "no rows returned"
    return data;
  },

  // Session Operations (Keep local for fast UI state)
  setCurrentUser: (user: User | null) => {
    if (user) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  },

  getCurrentUser: (): User | null => {
    const data = localStorage.getItem(SESSION_KEY);
    return data ? JSON.parse(data) : null;
  },

  // Scan Operations
  saveScan: async (scan: Omit<SavedScan, 'id' | 'timestamp'>) => {
    const newScan = {
      ...scan,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString()
    };

    const { data, error } = await supabase
      .from('scans')
      .insert([newScan])
      .select()
      .single();

    if (error) throw error;
    return data;
  },

  getUserScans: async (userId: string): Promise<SavedScan[]> => {
    const { data, error } = await supabase
      .from('scans')
      .select('*')
      .eq('userId', userId)
      .order('timestamp', { ascending: false });

    if (error) throw error;
    return data || [];
  }
};

import React, { useRef, useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import Scanner from './components/Scanner';
import WasteCategories from './components/WasteCategories';
import About from './components/About';
import Impact from './components/Impact';
import Tips from './components/Tips';
import Footer from './components/Footer';
import Login from './components/Login';
import Register from './components/Register';
import History from './components/History';
import { db } from './services/db';
import { User } from './types';

type View = 'landing' | 'login' | 'register' | 'history';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('landing');
  const [user, setUser] = useState<User | null>(null);
  const scannerRef = useRef<HTMLDivElement>(null);
  const aboutRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedUser = db.getCurrentUser();
    if (savedUser) setUser(savedUser);
  }, []);

  const scrollToScanner = () => {
    if (currentView !== 'landing') {
      setCurrentView('landing');
      setTimeout(() => {
        scannerRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      scannerRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const scrollToAbout = () => {
    if (currentView !== 'landing') {
      setCurrentView('landing');
      setTimeout(() => {
        aboutRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      aboutRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const navigateTo = (view: View) => {
    setCurrentView(view);
    window.scrollTo(0, 0);
  };

  const handleLogout = () => {
    db.setCurrentUser(null);
    setUser(null);
    navigateTo('landing');
  };

  const handleAuthSuccess = (userData: User) => {
    setUser(userData);
    navigateTo('landing');
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header 
        user={user}
        onStartScan={scrollToScanner} 
        onLoginClick={() => navigateTo('login')}
        onRegisterClick={() => navigateTo('register')}
        onHistoryClick={() => navigateTo('history')}
